import { useEffect } from "react";
import "./topbar.css";
import { NotificationsNone, Language, Settings } from "@material-ui/icons";
import { Link, useNavigate } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { logout } from "../../redux/apiCalls";
import { admin } from "../../requestMethods";
import { useTranslation } from "react-i18next";
import i18n from "i18next";


const Topbar = () => {
  const notifications = 2 
  const user = useSelector(state => state.user.currentUser);
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { i18n, t } = useTranslation(["topbar"]);
  console.log(useTranslation)
  
  const handleLanguage = (e) => {
    i18n.changeLanguage(e.target.value)
  };
  
  useEffect(() => {
    if (localStorage.getItem("i18nextLng")?.length > 2) {
      i18n.changeLanguage("en");
    }
  }, []);
  
  const handleClick = (e) => {
    e.preventDefault();
    logout(dispatch);
    navigate("/login")
  };

  return (
    {user} ?
      <div className="topbar">
        <div className="topbarWrapper">
          <div className="topLeft">
            <Link to="/" style={{ textDecoration: 'none'}}>
              <span className="logo">{t("logo")}</span>
            </Link>
          </div>
          <div className="topRight">
            {admin
              ? <button className="logoutButton" onClick={(e) => handleClick(e)}>Logout</button>
              : <Link to="/login" className="logoutButton">Login</Link>
            }
            <div className="topbarIconContainer">
              <NotificationsNone />
              <span className="topIconBadge">{notifications}</span>
            </div>
            <div className="topbarIconContainer">
              <Language />
              <select 
                className="selectLanguage"
                onChange={handleLanguage} 
                value={localStorage.getItem("i18nextLng")}
              >
                <option value="en">EN</option>
                <option value="ua">UA</option>
              </select>
            </div>
            <div className="topbarIconContainer">
              <Settings />
            </div>
            <img src="https://firebasestorage.googleapis.com/v0/b/shop-80015.appspot.com/o/grape-icon.png?alt=media&token=edb90e89-ed75-4e1d-b172-d92fdaba92bb" alt="" className="topAvatar" />
          </div>
        </div>
      </div>
      : navigate("/login")
  );
}

export default Topbar
